  1	import {
  2	  Alert,
  3	  Button,
  4	  Divider,
  5	  Dropdown,
  6	  DropdownItem,
  7	  DropdownList,
  8	  Flex,
  9	  FlexItem,
 10	  MenuToggle,
 11	  MenuToggleElement,
 12	  Modal,
 13	  ModalVariant,
 14	  NumberInput,
 15	} from '@patternfly/react-core';
 16	import * as React from 'react';
 17	import { TFunction, useTranslation } from 'react-i18next';
 18	import * as time from '../time';
 19	import { DateTimePicker } from './DateTimePicker';
 20	import { TimeUnitPicker } from './TimeUnitPicker';
 21	
 22	const CUSTOM_RANGE_KEY = 'CUSTOM_RANGE';
 23	const CUSTOM_DURATION_KEY = 'CUSTOM_DURATION';
 24	
 25	const timeRangeOptions = [
 26	  { key: '5m', period: new time.Duration(5, time.MINUTE) },
 27	  { key: '30m', period: new time.Duration(30, time.MINUTE) },
 28	  { key: '1h', period: new time.Duration(1, time.HOUR) },
 29	  { key: '1d', period: new time.Duration(1, time.DAY) },
 30	  { key: '1w', period: new time.Duration(1, time.WEEK) },
 31	];
 32	
 33	const keyFromPeriod = (period: time.Period): string => {
 34	  if (period instanceof time.Duration) {
 35	    const match = timeRangeOptions.find(
 36	      (o) => o.period.count === period.count && o.period.unit === period.unit,
 37	    );
 38	    if (match) return match.key;
 39	    return CUSTOM_DURATION_KEY;
 40	  }
 41	  return CUSTOM_RANGE_KEY;
 42	};
 43	
 44	const formatDate = (d: Date): string =>
 45	  d
 46	    .toLocaleString(undefined, { dateStyle: 'short', timeStyle: 'short', hour12: false })
 47	    .replace(/,/g, '');
 48	
 49	const labelFromPeriod = (period: time.Period, t: TFunction): string => {
 50	  if (period instanceof time.Duration) {
 51	    return `${t('Last')} ${period.count} ${t(period.unit.name)}`;
 52	  }
 53	  if (period instanceof time.Range) {
 54	    return `${formatDate(period.start)}–${formatDate(period.end)}`;
 55	  }
 56	  return t('Custom');
 57	};
 58	
 59	interface TimeRangeModalProps {
 60	  initialRange: time.Range;
 61	  onSave: (range: time.Range) => void;
 62	  onClose: () => void;
 63	}
 64	
 65	const TimeRangeModal: React.FC<TimeRangeModalProps> = ({ initialRange, onSave, onClose }) => {
 66	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
 67	  const [start, setStart] = React.useState(initialRange.start);
 68	  const [end, setEnd] = React.useState(initialRange.end);
 69	
 70	  const isValid = start < end;
 71	
 72	  return (
 73	    <Modal
 74	      variant={ModalVariant.small}
 75	      title={t('Custom time range')}
 76	      isOpen
 77	      onClose={onClose}
 78	      actions={[
 79	        <Button
 80	          key="save"
 81	          variant="primary"
 82	          onClick={() => onSave(new time.Range(start, end))}
 83	          isDisabled={!isValid}
 84	        >
 85	          {t('Save')}
 86	        </Button>,
 87	        <Button key="cancel" variant="link" onClick={onClose}>
 88	          {t('Cancel')}
 89	        </Button>,
 90	      ]}
 91	    >
 92	      <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsMd' }}>
 93	        <FlexItem>
 94	          <label>{t('From')}</label>
 95	          <DateTimePicker date={start} onChange={setStart} />
 96	        </FlexItem>
 97	        <FlexItem>
 98	          <label>{t('To')}</label>
 99	          <DateTimePicker date={end} onChange={setEnd} />
100	        </FlexItem>
101	        {!isValid && (
102	          <Alert variant="danger" isInline isPlain title={t('End time must be after start time')} />
103	        )}
104	      </Flex>
105	    </Modal>
106	  );
107	};
108	
109	interface DurationModalProps {
110	  initialDuration: time.Duration;
111	  onSave: (duration: time.Duration) => void;
112	  onClose: () => void;
113	}
114	
115	const DurationModal: React.FC<DurationModalProps> = ({ initialDuration, onSave, onClose }) => {
116	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
117	  const [count, setCount] = React.useState(initialDuration.count);
118	  const [unit, setUnit] = React.useState(initialDuration.unit);
119	
120	  const onChangeCount = (n: number) => setCount(Math.max(1, n || 1));
121	
122	  return (
123	    <Modal
124	      variant={ModalVariant.small}
125	      title={t('Custom duration')}
126	      isOpen
127	      onClose={onClose}
128	      actions={[
129	        <Button
130	          key="save"
131	          variant="primary"
132	          onClick={() => onSave(new time.Duration(count, unit))}
133	          isDisabled={count < 1}
134	        >
135	          {t('Save')}
136	        </Button>,
137	        <Button key="cancel" variant="link" onClick={onClose}>
138	          {t('Cancel')}
139	        </Button>,
140	      ]}
141	    >
142	      <Flex alignItems={{ default: 'alignItemsCenter' }} spaceItems={{ default: 'spaceItemsSm' }}>
143	        <FlexItem>{t('Last')}</FlexItem>
144	        <FlexItem>
145	          <NumberInput
146	            value={count}
147	            min={1}
148	            onPlus={() => onChangeCount(count + 1)}
149	            onMinus={() => onChangeCount(count - 1)}
150	            onChange={(e) => onChangeCount(Number((e.target as HTMLInputElement).value))}
151	            widthChars={3}
152	          />
153	        </FlexItem>
154	        <FlexItem>
155	          <TimeUnitPicker unit={unit} onChange={setUnit} />
156	        </FlexItem>
157	      </Flex>
158	    </Modal>
159	  );
160	};
161	
162	interface TimeRangeDropdownProps {
163	  period: time.Period;
164	  onChange: (period: time.Period) => void;
165	  className?: string;
166	}
167	
168	export const TimeRangeDropdown: React.FC<TimeRangeDropdownProps> = ({
169	  period,
170	  onChange,
171	  className,
172	}) => {
173	  const { t } = useTranslation('plugin__troubleshooting-panel-console-plugin');
174	  const [isOpen, setIsOpen] = React.useState(false);
175	  const [rangeModalOpen, setRangeModalOpen] = React.useState(false);
176	  const [durationModalOpen, setDurationModalOpen] = React.useState(false);
177	
178	  const selectedKey = keyFromPeriod(period);
179	
180	  const handleCustomRangeClick = () => {
181	    setIsOpen(false);
182	    setRangeModalOpen(true);
183	  };
184	
185	  const handleCustomDurationClick = () => {
186	    setIsOpen(false);
187	    setDurationModalOpen(true);
188	  };
189	
190	  const initialRange = React.useMemo(() => {
191	    const [start, end] = period.startEnd();
192	    return new time.Range(start, end);
193	  }, [period]);
194	
195	  const initialDuration = React.useMemo(
196	    () => (period instanceof time.Duration ? period : new time.Duration(1, time.DAY)),
197	    [period],
198	  );
199	
200	  return (
201	    <>
202	      <Dropdown
203	        isOpen={isOpen}
204	        onSelect={() => setIsOpen(false)}
205	        onOpenChange={setIsOpen}
206	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
207	          <MenuToggle
208	            ref={toggleRef}
209	            onClick={() => setIsOpen(!isOpen)}
210	            isExpanded={isOpen}
211	            className={className}
212	          >
213	            {labelFromPeriod(period, t)}
214	          </MenuToggle>
215	        )}
216	      >
217	        <DropdownList>
218	          {timeRangeOptions.map(({ key, period: optPeriod }) => (
219	            <DropdownItem
220	              key={key}
221	              isSelected={key === selectedKey}
222	              onClick={() => onChange(optPeriod)}
223	            >
224	              {labelFromPeriod(optPeriod, t)}
225	            </DropdownItem>
226	          ))}
227	          <Divider />
228	          <DropdownItem
229	            key={CUSTOM_DURATION_KEY}
230	            isSelected={selectedKey === CUSTOM_DURATION_KEY}
231	            onClick={handleCustomDurationClick}
232	          >
233	            {t('Other duration')}
234	          </DropdownItem>
235	          <DropdownItem
236	            key={CUSTOM_RANGE_KEY}
237	            isSelected={selectedKey === CUSTOM_RANGE_KEY}
238	            onClick={handleCustomRangeClick}
239	          >
240	            {t('Start-end time range')}
241	          </DropdownItem>
242	        </DropdownList>
243	      </Dropdown>
244	      {rangeModalOpen && (
245	        <TimeRangeModal
246	          initialRange={initialRange}
247	          onSave={(range) => {
248	            setRangeModalOpen(false);
249	            onChange(range);
250	          }}
251	          onClose={() => setRangeModalOpen(false)}
252	        />
253	      )}
254	      {durationModalOpen && (
255	        <DurationModal
256	          initialDuration={initialDuration}
257	          onSave={(duration) => {
258	            setDurationModalOpen(false);
259	            onChange(duration);
260	          }}
261	          onClose={() => setDurationModalOpen(false)}
262	        />
263	      )}
264	    </>
265	  );
266	};

